/** Whole-orbital descriptor. */
export function stdAlgoMazegen(params: StdAlgoMazegenParams): OrbitalDefinition {
  const entity: Entity = {
    name: params.entityName,
    fields: params.fields ?? [],
    persistence: 'runtime',
  };
  return makeOrbitalWithUses({
    name: 'MazeGenEngineOrbital',
    uses: [{ from: BEHAVIOR_PATH, as: ALIAS }],
    entity,
    traits: [
      stdAlgoMazegenTrait(params),
    ],
    pages: [
      stdAlgoMazegenPage(params),
    ],
  });
}
